  },
  except((error) => {
    if (error instanceof ErrorResponse) {
      return new Response(
        JSON.stringify({ error: error.message, code: error.code }),
        {
          status: error.code,
          headers: { "content-type": "application/json" },
        },
      );
    }
  }),
  route("/ok", () => new Response(JSON.stringify({ ok: true }), {
    status: 200,
    headers: { "content-type": "application/json" },
  })),
